// ── FPU Guard ────────────────────────────────────────────────────────────────
// D2D/D3D can change the FPU control word (single precision, masked exceptions).
// Programs like StartAllBack (Delphi) unmask FPU exceptions — any D2D call from
// our hooks corrupts their FPU state, causing "invalid floating point operation".
// FPUGuard saves/restores the FPU control word around D2D resource creation.
struct FPUGuard {
    unsigned int prev;
    FPUGuard()  { _controlfp_s(&prev, 0, 0); }
    ~FPUGuard() { _controlfp_s(nullptr, prev, _MCW_EM | _MCW_PC | _MCW_RC | _MCW_DN); }
};

