// One-shot marker: caption/backdrop already applied to this AeroWizard
// window's non-client area (see HandleThemeDraw).
static constexpr LPCWSTR kPropAeroWizardCaption = L"Win32UIModernizer.AeroWizardCaption";

// True if hwnd is inside a tracked AeroWizard window and isn't a real Win32
// control (Button/Edit/ComboBox) that should still get normal dark-mode
// styling. Used to keep our hooks from interfering with the AeroWizard
// control's own rendering.
static bool IsAeroWizardRawWindow(HWND hwnd)
{
    if (!hwnd) return false;
    wchar_t cls[64] = {};
    if (GetClassNameW(hwnd, cls, ARRAYSIZE(cls))) {
        if (_wcsicmp(cls, L"Button") == 0 || _wcsicmp(cls, L"Edit") == 0 ||
            _wcsicmp(cls, L"ComboBox") == 0)
            return false;
    }
    HWND root = GetAncestor(hwnd, GA_ROOT);
    return root && GetPropW(root, kPropAeroWizardCaption);
}

// One-shot marker: a modern Explorer-style file-picker #32770 dialog hosted
// in a dark-mode-excluded process, opted back into our real dark palette
// despite the process-wide exclusion (see TryForceDarkExcludedFilePicker).
static constexpr LPCWSTR kPropForceDarkFilePicker = L"Win32UIModernizer.ForceDarkFilePicker";

// True if hwnd's top-level ancestor is a tracked force-dark file picker.
// Consulted by GetSysColor_hook/GetSysColorBrush_hook -- those APIs take no
// HWND/HDC at all, so callers pass g_tlsPaintHwnd (last-BeginPaint-wins
// thread-local; can go stale if another window on this thread paints
// in between -- an accepted, pre-existing tradeoff already used the same
// way elsewhere in this file, e.g. IsWindowDarkMode's fallback chain).
static bool IsInsideForceDarkFilePicker(HWND hwnd)
{
    if (!hwnd) return false;
    HWND root = GetAncestor(hwnd, GA_ROOT);
    return root && GetPropW(root, kPropForceDarkFilePicker);
}

static std::mutex g_staticBrushCacheMutex;
static std::unordered_map<COLORREF, HBRUSH> g_staticBrushCache;

static HBRUSH GetCachedSolidBrush(COLORREF color)
{
    std::lock_guard<std::mutex> lk(g_staticBrushCacheMutex);
    auto it = g_staticBrushCache.find(color);
    if (it != g_staticBrushCache.end())
        return it->second;

    // Only bulk-cleared on theme change (StaticBrushCacheClear). Some callers
    // pass sampled or app-provided colors, so the set is effectively unbounded
    // -- cap the real GDI brush count instead of growing towards the
    // per-process GDI object quota.
    constexpr size_t kStaticBrushCacheMax = 64;
    if (g_staticBrushCache.size() >= kStaticBrushCacheMax) {
        for (auto& kv : g_staticBrushCache)
            if (kv.second)
                DeleteObject(kv.second);
        g_staticBrushCache.clear();
    }

    HBRUSH brush = CreateSolidBrush(color);
    if (brush)
        g_staticBrushCache.emplace(color, brush);
    return brush;
}

static void StaticBrushCacheClear()
{
    std::lock_guard<std::mutex> lk(g_staticBrushCacheMutex);
    for (auto& kv : g_staticBrushCache)
        if (kv.second)
            DeleteObject(kv.second);
    g_staticBrushCache.clear();
}

static ID2D1Factory1* EnsureD2DFactory()
{
    // g_d2dFactory is normally already set by Wh_ModInit's eager, single-
    // threaded creation, so this fast path is the common case and needs no
    // lock. The lock only guards the fallback path for the (unexpected)
    // case where that eager creation failed -- without it, two threads
    // racing here for the first time could both call D2D1CreateFactory and
    // clobber each other's write to this raw pointer.
    if (g_d2dFactory) return g_d2dFactory;
    static std::mutex s_factoryMutex;
    std::lock_guard<std::mutex> lk(s_factoryMutex);
    if (!g_d2dFactory)
    {
        FPUGuard fpu; // D2D1CreateFactory may change FPU control word
        D2D1_FACTORY_OPTIONS options = {};
        // MULTI_THREADED required: pill animation thread uses D2D from background thread
        D2D1CreateFactory(D2D1_FACTORY_TYPE_MULTI_THREADED, options, &g_d2dFactory);
    }
    return g_d2dFactory;
}

static UINT GetDpiFromMonitor()
{
    HMONITOR hPrimary = MonitorFromPoint({0,0}, MONITOR_DEFAULTTOPRIMARY);
    UINT dpiX = USER_DEFAULT_SCREEN_DPI, dpiY = USER_DEFAULT_SCREEN_DPI;
    if (SUCCEEDED(GetDpiForMonitor(hPrimary, MDT_EFFECTIVE_DPI, &dpiX, &dpiY)))
        return dpiY;
    return USER_DEFAULT_SCREEN_DPI;
}
