// Declared here (ahead of the main GLYPH_* block near the SVG path data)
// because IconPopPreDuration below needs it before that point in the file.
static const wchar_t GLYPH_ONEDRIVE[] = L"\uE753";
static const wchar_t GLYPH_DESKTOP[]   = L"\uE90E";
static const wchar_t GLYPH_THISPC[]    = L"\uE7F4";
static const wchar_t GLYPH_PICTURES[]  = L"\uEB9F";
static const wchar_t GLYPH_RECYCLE_FULL[] = L"\uE74B";
static const wchar_t GLYPH_RECYCLE[]   = L"\uE74D";
static const wchar_t GLYPH_PHONE[]     = L"\uE8EA";
static const wchar_t GLYPH_DRIVE[]     = L"\uEDA2";
static const wchar_t GLYPH_CDROM[]     = L"\uE958"; // Segoe Fluent Icons "CD"
static const wchar_t GLYPH_DOCUMENTS[] = L"\uE8A5";
static const wchar_t GLYPH_VIDEOS[]    = L"\uE714";
static const wchar_t GLYPH_HOME[]      = L"\uE80F";
static const wchar_t GLYPH_GALLERY[]   = L"\uE8B9";
static const wchar_t GLYPH_LIBRARY[]   = L"\uE8F1";
static const wchar_t GLYPH_FAVORITES[] = L"\uE734";
static const wchar_t GLYPH_FAVORITES_FILLED[] = L"\uE735";
static const wchar_t GLYPH_PROGFILES[] = L"\uE756";
static const wchar_t GLYPH_GOOGLEDRIVE[] = L"\uF1A0";
static const wchar_t GLYPH_NETWORK[]   = L"\uE774";
static const wchar_t GLYPH_ZIPARCHIVE[] = L"\uF012"; // Segoe Fluent Icons "ZipFolder"
