// Per-icon intro played before the regular pop (see DrawOneDriveWipeIn /
// DrawCrossfadeSingle / DrawPicturesSunOrbit / DrawRecycleArrowsReveal /
// DrawPhoneVibrate / DrawDesktopBloomRise / DrawThisPcCrtOn /
// DrawDriveSwirlOn). 0 for every other icon.
static const DOUBLE ICON_POP_WIPE_DUR_ONEDRIVE = 1.05; // blobs converge in the first 65%, remaining 35% is the grow-with-overshoot settle
static const DOUBLE ICON_POP_DESKTOP_FADE_DUR  = 0.35; // phase 1: Normal->Filled fade
static const DOUBLE ICON_POP_DESKTOP_BLOOM_DUR = 0.55; // phase 2: bloom rise + hold + fade
static const DOUBLE ICON_POP_WIPE_DUR_DESKTOP  = ICON_POP_DESKTOP_FADE_DUR + ICON_POP_DESKTOP_BLOOM_DUR;
static const DOUBLE ICON_POP_WIPE_DUR_THISPC   = 0.90; // CRT-on, slower shrink+ripple handoff, then spring back
static const DOUBLE ICON_POP_WIPE_DUR_PICTURES = 0.74; // full sun-orbit lap + fade
static const DOUBLE ICON_POP_WIPE_DUR_RECYCLE  = 0.70; // arrows trace in + fade
static const DOUBLE ICON_POP_WIPE_DUR_PHONE    = 0.50; // shake cycles + zigzag fade
static const DOUBLE ICON_POP_WIPE_DUR_DRIVE    = 0.80; // border trace + blink + fade to Filled
static const DOUBLE ICON_POP_WIPE_DUR_CDROM    = 0.72; // crossfade to a 2-hole Intermediate disc, spin a full turn, patch the holes back in
static const DOUBLE ICON_POP_WIPE_DUR_HOME     = 0.80; // pause + door overshoot + crossfade + grow back
static const DOUBLE ICON_POP_WIPE_DUR_DOCUMENTS = 0.70; // corner fold-in + fade to Filled
static const DOUBLE ICON_POP_WIPE_DUR_VIDEOS   = 0.70; // fill-reveal + wedge undraw/pop + fade to Filled
static const DOUBLE ICON_POP_WIPE_DUR_GALLERY  = 0.70; // shrink+separate, fill, snap back with overshoot, fade to Filled
static const DOUBLE ICON_POP_WIPE_DUR_LIBRARY  = 0.62; // three books fan out, return, then quick fade to Filled
static const DOUBLE ICON_POP_WIPE_DUR_FAVORITES = 0.62; // filled star pulses twice, then settles
static const DOUBLE ICON_POP_WIPE_DUR_PROGFILES = 0.75; // fill hops TL->BL->BR, fade to Filled
static const DOUBLE ICON_POP_WIPE_DUR_GOOGLEDRIVE = 0.75; // fill hops Top->Right->Left with scale pop; no crossfade needed since per-facet Filled geometry is pixel-identical to the combined Filled render
static const DOUBLE ICON_POP_WIPE_DUR_NETWORK  = 0.75; // radar sweep reveal + settle pulse + fade to Filled
static const DOUBLE ICON_POP_WIPE_DUR_ZIP      = 0.70; // unzip (halves slide apart + pull rises), zip closed with overshoot
static const DOUBLE ICON_POP_WIPE_DUR_FOLDER   = 0.28; // crossfade Normal->Filled (DrawCrossfadeSingle); no bespoke geometry intro
static DOUBLE IconPopPreDuration(const wchar_t* glyph) {
    if (!glyph) return 0.0;
    if (glyph[0] == GLYPH_ONEDRIVE[0]) return ICON_POP_WIPE_DUR_ONEDRIVE;
    if (glyph[0] == GLYPH_DESKTOP[0])  return ICON_POP_WIPE_DUR_DESKTOP;
    if (glyph[0] == GLYPH_THISPC[0])   return ICON_POP_WIPE_DUR_THISPC;
    if (glyph[0] == GLYPH_PICTURES[0]) return ICON_POP_WIPE_DUR_PICTURES;
    if (glyph[0] == GLYPH_RECYCLE[0] || glyph[0] == GLYPH_RECYCLE_FULL[0])
        return ICON_POP_WIPE_DUR_RECYCLE;
    if (glyph[0] == GLYPH_PHONE[0])    return ICON_POP_WIPE_DUR_PHONE;
    if (glyph[0] == GLYPH_DRIVE[0])    return ICON_POP_WIPE_DUR_DRIVE;
    if (glyph[0] == GLYPH_CDROM[0])    return ICON_POP_WIPE_DUR_CDROM;
    if (glyph[0] == GLYPH_HOME[0])     return ICON_POP_WIPE_DUR_HOME;
    if (glyph[0] == GLYPH_DOCUMENTS[0]) return ICON_POP_WIPE_DUR_DOCUMENTS;
    if (glyph[0] == GLYPH_VIDEOS[0])   return ICON_POP_WIPE_DUR_VIDEOS;
    if (glyph[0] == GLYPH_GALLERY[0])  return ICON_POP_WIPE_DUR_GALLERY;
    if (glyph[0] == GLYPH_LIBRARY[0])  return ICON_POP_WIPE_DUR_LIBRARY;
    if (glyph[0] == GLYPH_FAVORITES[0] || glyph[0] == GLYPH_FAVORITES_FILLED[0])
        return ICON_POP_WIPE_DUR_FAVORITES;
    if (glyph[0] == GLYPH_PROGFILES[0]) return ICON_POP_WIPE_DUR_PROGFILES;
    if (glyph[0] == GLYPH_GOOGLEDRIVE[0]) return ICON_POP_WIPE_DUR_GOOGLEDRIVE;
    if (glyph[0] == GLYPH_NETWORK[0])  return ICON_POP_WIPE_DUR_NETWORK;
    if (glyph[0] == GLYPH_ZIPARCHIVE[0]) return ICON_POP_WIPE_DUR_ZIP;
    if (glyph[0] == GLYPH_FOLDER[0])   return ICON_POP_WIPE_DUR_FOLDER;
    return 0.0;
}

static std::unordered_map<HWND, HTREEITEM> g_glyphActiveItem; // last active item per tree (UI thread only)

static void GlyphTreeOwnerCleanup(HWND hwnd)
{
    const bool hadPinList = GetPropW(hwnd, kPropPinList) != nullptr;
    bool removedTrackedTree = false;
    bool noTrackedTreesRemain = false;
    {
        std::lock_guard<std::mutex> lock(g_glyphTreeMutex);
        removedTrackedTree = g_glyphTrackedTrees.erase(hwnd) != 0;
        noTrackedTreesRemain = g_glyphTrackedTrees.empty();
    }
    g_glyphActiveItem.erase(hwnd);
    PinRestoreOriginalList(hwnd, true);
    if ((removedTrackedTree && noTrackedTreesRemain) || hadPinList)
        GlyphDWriteCacheClear();
}
