static HANDLE EnsureIconPopWakeEvent() {
    if (!g_iconPopWakeEvent)
        g_iconPopWakeEvent = CreateEventW(nullptr, FALSE, FALSE, nullptr);
    return g_iconPopWakeEvent;
}

static int IconPopComputeSleepMs(HWND hwnd)
{
    HMONITOR hMon = hwnd ? MonitorFromWindow(hwnd, MONITOR_DEFAULTTONEAREST)
                         : MonitorFromPoint({0, 0}, MONITOR_DEFAULTTOPRIMARY);
    MONITORINFOEXW mi = {};
    mi.cbSize = sizeof(mi);
    if (!GetMonitorInfoW(hMon, &mi))
        return 10;

    DEVMODEW dm = {};
    dm.dmSize = sizeof(dm);
    if (!EnumDisplaySettingsW(mi.szDevice, ENUM_CURRENT_SETTINGS, &dm) ||
        dm.dmDisplayFrequency < 24)
        return 10;

    int sleepMs = (int)(1000.0 / (double)dm.dmDisplayFrequency + 0.5);
    return std::clamp(sleepMs, 4, 16);
}

static bool IsClassName(HWND hwnd, LPCWSTR className)
{
    if (!hwnd || !className)
        return false;

    wchar_t cls[64] = {};
    return GetClassNameW(hwnd, cls, ARRAYSIZE(cls)) &&
           _wcsicmp(cls, className) == 0;
}

// Some SVG nav-pane icons (Desktop, OneDrive) are drawn at a reduced scale
// to visually match their neighbors, but only inside Explorer's main
// CabinetWClass window -- other hosts (dialogs, other pickers) get the
// icon at its normal uniform-fit size.
static bool IsHostedInCabinetWClass(HWND hwnd)
{
    HWND root = GetAncestor(hwnd, GA_ROOT);
    return root && IsClassName(root, L"CabinetWClass");
}

static bool IsTravelBandToolbarCustomDraw(HWND notifyTarget, const NMHDR* nm)
{
    if (!g_settings.ExplorerSection || !g_settings.LegacyRebarControls ||
        !nm || nm->code != NM_CUSTOMDRAW || !nm->hwndFrom)
        return false;

    if (!IsClassName(notifyTarget, L"TravelBand") ||
        !IsClassName(nm->hwndFrom, L"ToolbarWindow32"))
        return false;

    bool inRebar = false;
    for (HWND p = nm->hwndFrom; p; p = GetParent(p)) {
        if (IsClassName(p, L"ReBarWindow32")) {
            inRebar = true;
            break;
        }
    }
    if (!inRebar)
        return false;

    HWND root = GetAncestor(nm->hwndFrom, GA_ROOT);
    if (!root)
        return false;

    wchar_t rootCls[64] = {};
    if (!GetClassNameW(root, rootCls, ARRAYSIZE(rootCls)))
        return false;

    return _wcsicmp(rootCls, L"CabinetWClass") == 0 ||
           _wcsicmp(rootCls, L"ExploreWClass") == 0 ||
           _wcsicmp(rootCls, L"#32770") == 0 ||
           _wcsicmp(rootCls, L"NativeHWNDHost") == 0;
}

static COLORREF TravelBandEraseColor()
{
    const bool dark = g_darkModeActive;
    if (g_settings.RebarMicaTint && IsSystemTransparencyEnabled()) {
        auto blend = [](COLORREF base, COLORREF overlay, float alpha) -> COLORREF {
            alpha = std::clamp(alpha, 0.f, 1.f);
            auto ch = [alpha](BYTE a, BYTE b) -> BYTE {
                return static_cast<BYTE>(a + (b - a) * alpha + 0.5f);
            };
            return RGB(
                ch(GetRValue(base), GetRValue(overlay)),
                ch(GetGValue(base), GetGValue(overlay)),
                ch(GetBValue(base), GetBValue(overlay)));
        };

        const COLORREF micaBase = dark ? RGB(0x16, 0x16, 0x16)
                                       : RGB(0xFF, 0xFF, 0xFF);
        const COLORREF accent = GetAccentIndicator();
        const COLORREF base = blend(micaBase, accent, dark ? 0.15f : 0.08f);
        return blend(base,
                     dark ? RGB(0x49, 0x49, 0x49) : RGB(0xFF, 0xFF, 0xFF),
                     dark ? 0.12f : 0.50f);
    }

    // No mica tint: fixed colors instead of a queried/sampled background.
    return dark ? kPropDkBg
                : RGB(0xFF, 0xFF, 0xFF);
}

