static const wchar_t GLYPH_NAV_FORWARD[] = L"\uE72A";
static const wchar_t GLYPH_NAV_RECENT[]  = L"\uE70D";
// Up=E74A, Refresh=E72C -- same Segoe Fluent/MDL2 codepoint list.
static const wchar_t GLYPH_NAV_UP[]      = L"\uE74A";
static const wchar_t GLYPH_NAV_REFRESH[] = L"\uE72C";
// Classic Open/Save dialog top toolbar (NewFolder/View).
