// Legend swatch: full takeover for the three swatch control IDs, mirroring
// the "Disk Pie Chart" mod's proven technique of intercepting these exact
// control IDs. Rounded corners need anti-aliasing to not look jagged at
// this size, so this draws via this mod's existing D2D DC-render-target
// cache (CreateBoundD2DRenderTarget) rather than GDI FillRect/SetWindowRgn.
static void DiskPieDrawRoundedSwatch(HDC hdc, const RECT& rcItem, COLORREF color)
{
    float width = (float)(rcItem.right - rcItem.left);
    float height = (float)(rcItem.bottom - rcItem.top);
    if (width <= 0 || height <= 0)
    {
        return;
    }

    bool drewWithD2D = false;
    if (g_d2dFactory)
    {
        FPUGuard fpu;
        Microsoft::WRL::ComPtr<ID2D1DCRenderTarget> pRT;
        if (SUCCEEDED(CreateBoundD2DRenderTarget(hdc, &rcItem, g_d2dFactory, &pRT)))
        {
            Microsoft::WRL::ComPtr<ID2D1SolidColorBrush> brush;
            if (SUCCEEDED(pRT->CreateSolidColorBrush(ColorFAlpha(color), &brush)))
            {
                // Subtle 1px outline so the swatch reads as a distinct shape
                // against its own fill, not just a flat color blob.
                bool dark = IsWindowDarkMode(hdc);
                D2D1_COLOR_F borderColor = dark
                    ? D2D1::ColorF(1.0f, 1.0f, 1.0f, 0.10f)
                    : D2D1::ColorF(0.0f, 0.0f, 0.0f, 0.10f);

                float radius = (std::min)(3.0f, (std::min)(width, height) / 2.0f);
                D2D1_ROUNDED_RECT roundedRect = D2D1::RoundedRect(
                    D2D1::RectF(0.0f, 0.0f, width, height), radius, radius);

                pRT->BeginDraw();
                pRT->FillRoundedRectangle(roundedRect, brush.Get());
                brush->SetColor(borderColor);
                pRT->DrawRoundedRectangle(roundedRect, brush.Get(), 1.0f);
                HRESULT hr = pRT->EndDraw();
                if (hr == (HRESULT)D2DERR_RECREATE_TARGET)
                {
                    CachedTlsRTRecreate();
                }
                drewWithD2D = SUCCEEDED(hr);
            }
        }
    }

    if (!drewWithD2D)
    {
        // Fallback: square corners, but never fails to paint at all.
        HBRUSH hbr = CreateSolidBrush(color);
        FillRect(hdc, &rcItem, hbr);
        DeleteObject(hbr);
    }
}

// The "free"/"cache" swatches must keep their existing color exactly — that
// color is intentionally not hardcoded or guessed here. Instead, the real
// original handler is asked to draw once into an offscreen bitmap, and the
// resulting pixel is sampled, so the value is always correct for the
// current Windows build and theme without this mod needing to know it.
static COLORREF DiskPieSampleOriginalSwatchColor(void* lpps, LPDRAWITEMSTRUCT lpdi,
    void (__fastcall *original)(void*, LPDRAWITEMSTRUCT))
{
    int width = lpdi->rcItem.right - lpdi->rcItem.left;
    int height = lpdi->rcItem.bottom - lpdi->rcItem.top;
    if (width <= 0 || height <= 0)
    {
        return RGB(0xAC, 0xAC, 0xAC); // Never used unless rcItem is degenerate.
    }

    HDC hMemDC = CreateCompatibleDC(lpdi->hDC);
    HBITMAP hBmp = CreateCompatibleBitmap(lpdi->hDC, width, height);
    HBITMAP hOldBmp = (HBITMAP)SelectObject(hMemDC, hBmp);

    DRAWITEMSTRUCT diCopy = *lpdi;
    diCopy.hDC = hMemDC;
    diCopy.rcItem = RECT{ 0, 0, width, height };
    original(lpps, &diCopy);

    COLORREF color = GetPixel(hMemDC, width / 2, height / 2);

    SelectObject(hMemDC, hOldBmp);
    DeleteObject(hBmp);
    DeleteDC(hMemDC);

    return color;
}

static void (__fastcall *g_pDiskPieDrvPrshtDrawItem_Orig)(void*, LPDRAWITEMSTRUCT);
static void __fastcall DiskPieDrvPrshtDrawItem_Hook(void* lpps, LPDRAWITEMSTRUCT lpdi)
{
    if (!g_settings.DiskChartAccentColor)
    {
        g_pDiskPieDrvPrshtDrawItem_Orig(lpps, lpdi);
        return;
    }

    if (lpdi->CtlID == IDC_DRV_USEDCOLOR)
    {
        // Mirrors DiskPieResolveColor's full-disk bypass: keep the legend
        // consistent with whatever warning color the chart itself is
        // showing instead of forcing the accent color over it.
        COLORREF fillColor;
        if (DiskPieIsFull())
        {
            fillColor = DiskPieSampleOriginalSwatchColor(lpps, lpdi, g_pDiskPieDrvPrshtDrawItem_Orig);
        }
        else
        {
            bool dark = IsWindowDarkMode(lpdi->hDC);
            fillColor = GetAccentFromPalette(dark ? 4 : 16);
        }
        DiskPieDrawRoundedSwatch(lpdi->hDC, lpdi->rcItem, fillColor);
        return;
    }

    if (lpdi->CtlID == IDC_DRV_FREECOLOR || lpdi->CtlID == IDC_DRV_CACHECOLOR)
    {
        COLORREF original = DiskPieSampleOriginalSwatchColor(lpps, lpdi, g_pDiskPieDrvPrshtDrawItem_Orig);
        COLORREF fillColor = IsWindowDarkMode(lpdi->hDC) ? kDiskPieFreeColorDark : original;
        DiskPieDrawRoundedSwatch(lpdi->hDC, lpdi->rcItem, fillColor);
        return;
    }

    g_pDiskPieDrvPrshtDrawItem_Orig(lpps, lpdi);
}

