// PART 8 — Updated hooks + lifecycle


// ============================================================================
// Registry Editor modernization — placeholder (to be rebuilt)
// ============================================================================

// ============================================================================

constexpr INT TVP_TREEITEM_ = 1;
constexpr INT LVP_LISTITEM_ = 1;
constexpr UINT   TVM_GETNEXTITEM_  = 0x110A;
constexpr WPARAM TVGN_PARENT_      = 0x0003;
constexpr WPARAM TVGN_DROPHILITE_  = 0x0008;
constexpr WPARAM TVGN_CARET_       = 0x0009;

// Visual tree nesting depth of 'item' (0 = top-level row) and its real
// horizontal indent in device pixels relative to its own top-level ancestor.
// The indent is measured via TVM_GETITEMRECT rather than assumed, since the
// tree's actual per-level pixel step depends on whether items show an
// expand chevron or just an icon.
//
// A plain "has a parent" check is not enough to find the top-level ancestor:
// Explorer's nav pane has a hidden root (Desktop) above every visually
// top-level item, so TVGN_PARENT_ on those still returns a non-null handle --
// climbing stops one level early (at the item whose parent has no parent).
// Last successfully measured indent per (tree, item) -- TVM_GETITEMRECT
// fails for an item that's scrolled out of view (e.g. the item a blind
// transition is collapsing away from), which would otherwise report 0
// (no inset) for that one transition's collapse phase even though the
// item genuinely is nested. Falling back to the last known-good value is
// more often correct than a hard 0.
static HWND      s_pillNestLastHwnd     = nullptr;
static HTREEITEM s_pillNestLastItem     = nullptr;
static int       s_pillNestLastIndentPx = 0;

static void PillItemNestInfo(HWND tv, HTREEITEM item, int* outDepth, int* outIndentPx)
{
    *outDepth = 0;
    *outIndentPx = 0;
    if (!tv || !item) return;

    HTREEITEM top = item;
    int depth = 0;
    for (int i = 0; i < PILL_NEST_WALK_SAFETY_CAP; i++)
    {
        HTREEITEM parent = (HTREEITEM)SendMessageW(tv, TVM_GETNEXTITEM_, TVGN_PARENT_, (LPARAM)top);
        HTREEITEM grandparent = parent ? (HTREEITEM)SendMessageW(tv, TVM_GETNEXTITEM_, TVGN_PARENT_, (LPARAM)parent) : nullptr;
        if (!grandparent) break; // 'top' is already visually top-level
        top = parent;
        depth++;
    }
    *outDepth = depth;
    if (top == item) return;

    RECT rcItem = {}; *reinterpret_cast<HTREEITEM*>(&rcItem) = item;
    RECT rcTop  = {}; *reinterpret_cast<HTREEITEM*>(&rcTop)  = top;
    if (!SendMessageW(tv, TVM_GETITEMRECT, TRUE, (LPARAM)&rcItem) ||
        !SendMessageW(tv, TVM_GETITEMRECT, TRUE, (LPARAM)&rcTop))
    {
        if (tv == s_pillNestLastHwnd && item == s_pillNestLastItem)
            *outIndentPx = s_pillNestLastIndentPx;
        return;
    }

    int delta = rcItem.left - rcTop.left;
    if (delta < 0) delta = 0;
    if (delta > (int)PILL_NESTED_MAX_INDENT) delta = (int)PILL_NESTED_MAX_INDENT;
    *outIndentPx = delta;

    s_pillNestLastHwnd     = tv;
    s_pillNestLastItem     = item;
    s_pillNestLastIndentPx = delta;
}

// True if 'item' is currently visible (not hidden behind a collapsed
// ancestor). TVM_GETITEMRECT fails for a hidden item -- used to tell a
// plain navigation exit (the previous item is still shown, just no longer
// selected) apart from a collapse-triggered exit (the previous item's row
// was removed and everything below it shifted up).
static bool PillItemIsVisible(HWND tv, HTREEITEM item)
{
    if (!tv || !item) return false;
    RECT rc = {}; *reinterpret_cast<HTREEITEM*>(&rc) = item;
    return SendMessageW(tv, TVM_GETITEMRECT, TRUE, (LPARAM)&rc) != 0;
}

struct ShellDuiListItemDrawContext
{
    HWND hwnd = nullptr;
    RECT rc = {};
    int offset = 0;
    int offsetY = 0;
    int inflate = 0;
    DWORD tick = 0;
};

static thread_local ShellDuiListItemDrawContext g_shellDuiListItemCtx[24];
static thread_local UINT g_shellDuiListItemCtxNext = 0;

static bool IsShellDefViewDirectUI(HWND hwnd)
{
    if (!hwnd || !IsWindow(hwnd))
        return false;

    wchar_t cls[64] = {};
    if (!GetClassNameW(hwnd, cls, ARRAYSIZE(cls)) ||
        _wcsicmp(cls, L"DirectUIHWND") != 0)
        return false;

    return IsInsideShellFolderView(hwnd);
}

static void TrackShellDuiListItemForCheckbox(
    HDC hdc, const std::wstring& cls, INT part, INT state, LPCRECT rc)
{
    if (!g_settings.ExplorerSection || !g_settings.ListViewPill ||
        !rc || cls != L"ListView" || part != LVP_LISTITEM_)
        return;

    HWND hwnd = GetPaintHwndFromDC(hdc);
    if (!IsShellDefViewDirectUI(hwnd))
        return;

    const int w = rc->right - rc->left;
    const int h = rc->bottom - rc->top;
    if (w <= 0 || h <= 0)
        return;

    const UINT dpi = hwnd ? GetDpiForWindow(hwnd) : (UINT)g_Dpi;
    const float ratio = (float)w / (float)h;
    const int logicalHeight = MulDiv(h, 96, dpi);
    const int logicalExtent = MulDiv((w > h) ? w : h, 96, dpi);

    int logicalOffset = 0;
    int logicalOffsetY = 0;
    int logicalInflate = 0;
    if (ratio >= 2.5f)
    {
        logicalOffset = (logicalHeight <= 28) ? 0 : 6;
        logicalInflate = (logicalOffset == 6) ? 1 : 0;
    }
    else
    {
        if (logicalExtent >= 220)
        {
            logicalInflate = 4;
            logicalOffset = 4;
            logicalOffsetY = 4;
        }
        else if (logicalExtent >= 150)
        {
            logicalInflate = 3;
            logicalOffset = 2;
            logicalOffsetY = 2;
        }
        else if (logicalExtent >= 96)
        {
            logicalInflate = 2;
            logicalOffset = 2;
            logicalOffsetY = 2;
        }
        else
        {
            logicalInflate = 1;
        }
    }

    const int offset = MulDiv(logicalOffset, dpi, 96);
    const int offsetY = MulDiv(logicalOffsetY, dpi, 96);
    const int inflate = MulDiv(logicalInflate, dpi, 96);

    ShellDuiListItemDrawContext& ctx =
        g_shellDuiListItemCtx[g_shellDuiListItemCtxNext % ARRAYSIZE(g_shellDuiListItemCtx)];
    g_shellDuiListItemCtxNext++;
    ctx.hwnd = hwnd;
    ctx.rc = *rc;
    ctx.offset = offset;
    ctx.offsetY = offsetY;
    ctx.inflate = inflate;
    ctx.tick = GetTickCount();
}

static bool GetShellDuiCheckboxMetrics(
    HDC hdc, LPCRECT rc, int* offset, int* offsetY, int* inflate)
{
    if (!g_settings.ExplorerSection || !g_settings.ListViewPill ||
        !rc || !offset || !offsetY || !inflate)
        return false;

    HWND hwnd = GetPaintHwndFromDC(hdc);
    if (!IsShellDefViewDirectUI(hwnd))
        return false;

    const DWORD now = GetTickCount();
    ShellDuiListItemDrawContext* best = nullptr;
    for (ShellDuiListItemDrawContext& ctx : g_shellDuiListItemCtx) {
        if (ctx.hwnd != hwnd || now - ctx.tick > 5000)
            continue;

        const RECT& item = ctx.rc;
        if (rc->left >= item.left && rc->right <= item.right &&
            rc->top >= item.top && rc->bottom <= item.bottom &&
            (!best || ctx.tick >= best->tick)) {
            best = &ctx;
        }
    }
    if (!best)
        return false;

    *offset = best->offset;
    *offsetY = best->offsetY;
    *inflate = best->inflate;
    return true;
}

static bool PaintShiftedShellDuiCheckbox(HDC hdc, INT part, INT state, LPCRECT rc)
{
    if (!g_settings.ExplorerSection || !g_settings.ListViewPill ||
        !g_settings.CheckBoxAnim || part != BP_CHECKBOX || !rc)
        return false;

    int offset = 0;
    int offsetY = 0;
    int inflate = 0;
    if (!GetShellDuiCheckboxMetrics(hdc, rc, &offset, &offsetY, &inflate))
        return false;

    RECT shifted = *rc;
    OffsetRect(&shifted, offset, offsetY);
    if (inflate > 0)
        InflateRect(&shifted, inflate, inflate);
    return PaintCheckBox(hdc, part, state, &shifted);
}

