static void FileOpAccentGdipInit()
{
    HMODULE hGdiplus = LoadLibraryExW(L"gdiplus.dll", nullptr, LOAD_LIBRARY_SEARCH_SYSTEM32);
    if (!hGdiplus) return;

    g_pFileOpGdipGetBrushType =
        (FileOpGdipGetBrushType_t)GetProcAddress(hGdiplus, "GdipGetBrushType");
    g_pFileOpGdipGetSolidFillColor =
        (FileOpGdipGetSolidFillColor_t)GetProcAddress(hGdiplus, "GdipGetSolidFillColor");
    g_pFileOpGdipSetSolidFillColor =
        (FileOpGdipSetSolidFillColor_t)GetProcAddress(hGdiplus, "GdipSetSolidFillColor");
    g_pFileOpGdipGetLineColors =
        (FileOpGdipGetLineColors_t)GetProcAddress(hGdiplus, "GdipGetLineColors");
    g_pFileOpGdipSetLineColors =
        (FileOpGdipSetLineColors_t)GetProcAddress(hGdiplus, "GdipSetLineColors");
    g_pFileOpGdipGetPenColor =
        (FileOpGdipGetPenColor_t)GetProcAddress(hGdiplus, "GdipGetPenColor");
    g_pFileOpGdipSetPenColor =
        (FileOpGdipSetPenColor_t)GetProcAddress(hGdiplus, "GdipSetPenColor");

    struct { const char* name; void* hookFn; void** origFn; } hooks[] = {
        { "GdipFillPolygon",      (void*)FileOp_GdipFillPolygon_Hook,      (void**)&FileOp_GdipFillPolygon_Orig },
        { "GdipFillPolygonI",     (void*)FileOp_GdipFillPolygonI_Hook,     (void**)&FileOp_GdipFillPolygonI_Orig },
        { "GdipFillRectangleI",   (void*)FileOp_GdipFillRectangleI_Hook,   (void**)&FileOp_GdipFillRectangleI_Orig },
        { "GdipFillRectangle",    (void*)FileOp_GdipFillRectangle_Hook,    (void**)&FileOp_GdipFillRectangle_Orig },
        { "GdipDrawLines",        (void*)FileOp_GdipDrawLines_Hook,        (void**)&FileOp_GdipDrawLines_Orig },
        { "GdipDrawLinesI",       (void*)FileOp_GdipDrawLinesI_Hook,       (void**)&FileOp_GdipDrawLinesI_Orig },
        { "GdipDrawLine",         (void*)FileOp_GdipDrawLine_Hook,         (void**)&FileOp_GdipDrawLine_Orig },
        { "GdipDrawLineI",        (void*)FileOp_GdipDrawLineI_Hook,        (void**)&FileOp_GdipDrawLineI_Orig },
        { "GdipDrawPath",         (void*)FileOp_GdipDrawPath_Hook,         (void**)&FileOp_GdipDrawPath_Orig },
        { "GdipDrawClosedCurve",  (void*)FileOp_GdipDrawClosedCurve_Hook,  (void**)&FileOp_GdipDrawClosedCurve_Orig },
        { "GdipDrawClosedCurveI", (void*)FileOp_GdipDrawClosedCurveI_Hook, (void**)&FileOp_GdipDrawClosedCurveI_Orig },
        { "GdipDrawCurve",        (void*)FileOp_GdipDrawCurve_Hook,        (void**)&FileOp_GdipDrawCurve_Orig },
        { "GdipDrawCurveI",       (void*)FileOp_GdipDrawCurveI_Hook,       (void**)&FileOp_GdipDrawCurveI_Orig },
        { "GdipDrawPolygon",      (void*)FileOp_GdipDrawPolygon_Hook,      (void**)&FileOp_GdipDrawPolygon_Orig },
        { "GdipDrawPolygonI",     (void*)FileOp_GdipDrawPolygonI_Hook,     (void**)&FileOp_GdipDrawPolygonI_Orig },
        { "GdipDrawRectangle",    (void*)FileOp_GdipDrawRectangle_Hook,    (void**)&FileOp_GdipDrawRectangle_Orig },
        { "GdipDrawRectangleI",   (void*)FileOp_GdipDrawRectangleI_Hook,   (void**)&FileOp_GdipDrawRectangleI_Orig },
    };
    for (const auto& h : hooks) {
        FARPROC proc = GetProcAddress(hGdiplus, h.name);
        if (proc) {
            Wh_SetFunctionHook((void*)proc, h.hookFn, h.origFn);
        }
    }
}

// ============================================================================
// AutoPlay flyout replacement (ExplorerSection.AutoPlayReplacement)
// ============================================================================
// Replaces the Windows 11 AutoPlay flyout (Shell_Flyout window, shown when a
// removable drive/disc arrives) with a Direct2D popup: dark/light acrylic,
// real shell icons, entrance animation, accent-colored hover pill, correct
// handler invocation. Ported from the standalone "AutoPlay Replacement" mod;
// reuses this file's own infrastructure instead of duplicating it:
//   - GetAccentFromPalette()+ColorFAlpha() instead of its own palette reader
//   - IsSystemDarkMode() instead of its own registry read
//   - g_d2dFactory (already created for all processes) instead of its own D2D factory
//   - g_pSWCA/ACCENT_POLICY/WCA_ACCENT_POLICY (already loaded by CbdLoadAPIs)
//     instead of its own SetWindowCompositionAttribute plumbing
//   - IsCurrentProcessExplorer() to scope hook installation to Explorer only
//     (the flyout never appears anywhere else, and ShowWindow/SetWindowPos/
//     DestroyWindow are too hot-path to hook in every process under @include *)
// All symbols are Ap-prefixed: plain names like WndProc/ApplyAcrylic/g_pSWCA
// already exist in this file for unrelated features.

struct ApItem {
    std::wstring id;
    std::wstring action;
    std::wstring provider;
    std::wstring iconSpec;
    std::wstring invokeProgID;
    std::wstring invokeVerb;
    bool         isDefault  = false;
};

static constexpr wchar_t kApBaseKey[] =
    L"SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\AutoPlayHandlers";

static std::wstring ApRegSz(HKEY root, const wchar_t* sub, const wchar_t* val) {
    wchar_t buf[1024] = {};
    DWORD cb = sizeof(buf);
    RegGetValueW(root, sub, val,
                 RRF_RT_REG_SZ | RRF_ZEROONFAILURE, nullptr, buf, &cb);
    return buf;
}

static std::wstring ApIndirect(const std::wstring& s) {
    if (s.empty() || (s[0] != L'@' && s[0] != L'%')) return s;
    wchar_t out[1024] = {};
    if (SUCCEEDED(SHLoadIndirectString(s.c_str(), out, 1024, nullptr)) && out[0])
        return out;
    return s;
}

static bool ApIsFormatString(const std::wstring& s) {
    return s.find(L"!ls!") != std::wstring::npos ||
           s.find(L"!c!")  != std::wstring::npos ||
           s.find(L"%1")   != std::wstring::npos ||
           s.find(L"%2")   != std::wstring::npos;
}

// Try a list of @dll,-ID references in order, returning the first that
// produces a non-empty, non-format-string result.
// Falls back to the last entry if all indirect loads fail.
static std::wstring ApIndirectFallback(
    std::initializer_list<const wchar_t*> candidates) {
    for (const wchar_t* ref : candidates) {
        if (ref[0] != L'@' && ref[0] != L'%') return ref; // plain string
        std::wstring r = ApIndirect(ref);
        if (!r.empty() && !ApIsFormatString(r)) return r;
    }
    return L"";
}

static bool ApLoadItem(const wchar_t* name, const wchar_t* ct, ApItem& out) {
    wchar_t ucPath[MAX_PATH];
    swprintf_s(ucPath, L"%s\\UserChosenExecuteHandlers\\%s", kApBaseKey, ct);
    out.isDefault = (ApRegSz(HKEY_CURRENT_USER, ucPath, nullptr) == name);

    wchar_t hPath[MAX_PATH];
    swprintf_s(hPath, L"%s\\Handlers\\%s", kApBaseKey, name);
    HKEY hKey = nullptr;
    if (RegOpenKeyExW(HKEY_LOCAL_MACHINE, hPath, 0, KEY_READ, &hKey) != ERROR_SUCCESS &&
        RegOpenKeyExW(HKEY_CURRENT_USER,  hPath, 0, KEY_READ, &hKey) != ERROR_SUCCESS)
        return false;

    auto rv = [&](const wchar_t* v) -> std::wstring {
        wchar_t b[1024] = {}; DWORD cb = sizeof(b);
        RegQueryValueExW(hKey, v, nullptr, nullptr, (LPBYTE)b, &cb);
        return b;
    };
    out.id           = name;
    out.action       = ApIndirect(rv(L"Action"));
    out.provider     = ApIndirect(rv(L"Provider"));
    out.iconSpec     = rv(L"DefaultIcon");
    out.invokeProgID = rv(L"InvokeProgID");
    out.invokeVerb   = rv(L"InvokeVerb");
    RegCloseKey(hKey);
    // InvokeCLSID/InitCmdLine handlers use IHWEventHandler, a different COM
    // contract. Don't display an action unless this replacement can invoke its
    // registered ProgID + verb faithfully.
    return !out.action.empty() && !out.invokeProgID.empty();
}

// Locale-aware strings for MSOpenFolder and MSTakeNoAction.
// These strings are NOT available as RT_STRING resources in any Windows DLL --
// they are compiled directly into Windows.UI.Immersive.dll. We maintain
// translations for the most common UI languages; anything not listed falls
// back to English (correct, just not localized).
struct ApLocaleEntry { WORD lang; const wchar_t* text; };

static std::wstring ApLocaleString(const wchar_t* enUS,
    std::initializer_list<ApLocaleEntry> translations) {
    WORD primary = PRIMARYLANGID(GetUserDefaultUILanguage());
    for (const auto& e : translations) {
        if (e.lang == primary) return e.text;
    }
    return enUS;
}

