// openFolderLast=true  -> [content handlers, MSOpenFolder, MSTakeNoAction]
// openFolderLast=false -> [MSOpenFolder, content handlers, MSTakeNoAction]
static std::vector<ApItem> ApEnumItems(
    const std::vector<std::wstring>& types,
    const wchar_t* root,
    bool openFolderLast) {

    std::vector<ApItem> items;
    std::set<std::wstring>   seen;

    auto makeOpenFolder = [&]() -> ApItem {
        ApItem a;
        a.id       = L"MSOpenFolder";
        a.action   = ApStringOpenFolder();
        a.provider = ApStringFileExplorer();
        a.iconSpec = L"%SystemRoot%\\System32\\shell32.dll,3";
        return a;
    };

    // 1. "Open folder" FIRST for USB/storage
    if (!openFolderLast) {
        items.push_back(makeOpenFolder());
        seen.insert(L"MSOpenFolder");
    }

    // 2. Registry handlers per content type. Direct autorun.inf execution is
    // deliberately excluded; modern Windows no longer trusts removable media
    // to advertise an arbitrary executable as an AutoPlay action.
    for (const auto& ct : types) {
        wchar_t path[MAX_PATH];
        swprintf_s(path, MAX_PATH, L"%s\\EventHandlers\\%s", kApBaseKey, ct.c_str());
        for (HKEY hRoot : {HKEY_LOCAL_MACHINE, HKEY_CURRENT_USER}) {
            HKEY hKey = nullptr;
            if (RegOpenKeyExW(hRoot, path, 0, KEY_READ, &hKey) != ERROR_SUCCESS)
                continue;
            wchar_t name[256];
            for (DWORD i = 0; ; i++) {
                DWORD cch = ARRAYSIZE(name);
                if (RegEnumValueW(hKey, i, name, &cch,
                                  nullptr, nullptr, nullptr, nullptr) != ERROR_SUCCESS)
                    break;
                if (!seen.insert(name).second) continue;
                ApItem item;
                if (ApLoadItem(name, ct.c_str(), item)) {
                    // SettingsHandlers_StorageSense.dll,-200 is a white
                    // monochrome icon -- invisible in light mode. Use the
                    // generic storage icon from imageres.dll instead.
                    if (item.id == L"MSStorageSense")
                        item.iconSpec = L"%SystemRoot%\\System32\\imageres.dll,-32";
                    items.push_back(std::move(item));
                }
            }
            RegCloseKey(hKey);
        }
    }

    // 3. "Open folder" LAST for optical media
    if (openFolderLast && !seen.count(L"MSOpenFolder")) {
        items.push_back(makeOpenFolder());
        seen.insert(L"MSOpenFolder");
    }

    // 4. "Take no action" -- always last, closes dialog
    {
        ApItem n;
        n.id       = L"MSTakeNoAction";
        n.action   = ApStringTakeNoAction();
        n.provider = ApIndirectFallback({L"@autoplay.dll,-3", L"Windows"});
        n.iconSpec = L"%SystemRoot%\\System32\\imageres.dll,-98";
        items.push_back(std::move(n));
    }

    return items;
}

// Optimization: skip filesystem checks that are irrelevant for the drive type.
// DRIVE_CDROM: optical media -- only check optical content types and autorun.
//              No need to scan for DCIM/mp3/jpg (extremely rare on optical).
// DRIVE_REMOVABLE: flash/card -- skip optical-only types (BDMV, VIDEO_TS, *.cda).
static std::vector<std::wstring> ApDetectTypes(const wchar_t* root, UINT driveType) {
    std::vector<std::wstring> t;
    auto folder = [&](const wchar_t* n) {
        wchar_t p[MAX_PATH]; swprintf_s(p, L"%s%s", root, n);
        DWORD a = GetFileAttributesW(p);
        return a != INVALID_FILE_ATTRIBUTES && (a & FILE_ATTRIBUTE_DIRECTORY);
    };
    auto files = [&](const wchar_t* pat) {
        wchar_t p[MAX_PATH]; swprintf_s(p, L"%s%s", root, pat);
        WIN32_FIND_DATAW fd;
        HANDLE h = FindFirstFileW(p, &fd);
        if (h == INVALID_HANDLE_VALUE) return false;
        FindClose(h); return true;
    };

    if (driveType == DRIVE_CDROM) {
        if (folder(L"BDMV"))     t.push_back(L"BluRayOnArrival");
        if (folder(L"VIDEO_TS")) t.push_back(L"PlayDVDMovieOnArrival");
        if (files(L"*.cda"))     t.push_back(L"PlayCDAudioOnArrival");
    } else {
        if (folder(L"DCIM")) t.push_back(L"CameraMemoryOnArrival");
        bool v = files(L"*.mp4") || files(L"*.avi") || files(L"*.mkv");
        bool m = files(L"*.mp3") || files(L"*.flac") || files(L"*.aac");
        bool i = files(L"*.jpg") || files(L"*.jpeg") || files(L"*.png");
        if ((int)v + (int)m + (int)i >= 2) t.push_back(L"MixedContentOnArrival");
        if (v) t.push_back(L"VideoFilesOnArrival");
        if (m) t.push_back(L"MusicFilesOnArrival");
        if (i && !folder(L"DCIM")) t.push_back(L"ImageFilesOnArrival");
    }
    t.push_back(L"StorageOnArrival");
    return t;
}

// Helper: create a text format trying preferred fonts with fallbacks.
static Microsoft::WRL::ComPtr<IDWriteTextFormat> ApCreateFormat(
    IDWriteFactory* dw, float size,
    DWRITE_FONT_WEIGHT weight = DWRITE_FONT_WEIGHT_NORMAL) {
    Microsoft::WRL::ComPtr<IDWriteTextFormat> fmt;
    const wchar_t* fonts[] = {
        L"Segoe UI Variable Text",
        L"Segoe UI Variable",
        L"Segoe UI",
    };
    for (const wchar_t* name : fonts) {
        if (SUCCEEDED(dw->CreateTextFormat(
                name, nullptr, weight,
                DWRITE_FONT_STYLE_NORMAL, DWRITE_FONT_STRETCH_NORMAL,
                size, L"", &fmt)) && fmt)
            break;
    }
    if (fmt) fmt->SetWordWrapping(DWRITE_WORD_WRAPPING_NO_WRAP);
    return fmt;
}

static bool ApEnableEllipsis(
    IDWriteFactory* dw,
    const Microsoft::WRL::ComPtr<IDWriteTextFormat>& format,
    Microsoft::WRL::ComPtr<IDWriteInlineObject>& trimmingSign)
{
    if (!dw || !format ||
        FAILED(dw->CreateEllipsisTrimmingSign(format.Get(), &trimmingSign)) ||
        !trimmingSign)
        return false;

    DWRITE_TRIMMING trimming = {};
    trimming.granularity = DWRITE_TRIMMING_GRANULARITY_CHARACTER;
    return SUCCEEDED(format->SetTrimming(&trimming, trimmingSign.Get()));
}

