static constexpr D2D1_COLOR_F kApClrText   = {1.0f,  1.0f,  1.0f,  1.0f};
static constexpr D2D1_COLOR_F kApClrSub    = {0.62f, 0.62f, 0.62f, 1.0f};
static constexpr D2D1_COLOR_F kApClrIcon   = {0.28f, 0.28f, 0.28f, 0.55f};
static constexpr D2D1_COLOR_F kApClrSep    = {1.0f,  1.0f,  1.0f,  0.06f};
// Colors -- light mode
