// ── Shell image index to glyph map ───────────────────────────────────────
// Populated on a background thread (see GlyphBuildMapThreadProc) -- building
// this touches dozens of synchronous shell/COM calls (SHGetFileInfoW,
// SHParseDisplayName, ...) that can stall for seconds on a slow/disconnected
// network drive, a reconnecting cloud-sync provider (OneDrive/Google Drive),
// or awkward removable/optical media. g_glyphMapMutex guards these two maps
// plus g_glyphProgFilesNames/g_glyphPhoneNames below, all written by that
// background thread and read from the UI thread during per-item paint.
static std::mutex g_glyphMapMutex;
// Number of in-flight glyph background threads (build + drive-arrival
// refresh) -- Wh_ModUninit waits (bounded) for this to reach 0 before the
// DLL unloads out from under a still-running thread.
static std::atomic<int> g_glyphBgThreadCount{0};
static std::unordered_map<int, const wchar_t*> g_glyphIndexMap;
static std::unordered_map<int, const wchar_t*> g_glyphFilledMap;
static std::unordered_map<std::wstring, const wchar_t*> g_glyphKnownFolderNames;

// General SVG path parser: supports M/L/H/V/C/S/Q/T/Z (absolute + relative).
// Arcs (A/a) are approximated as a straight line to the endpoint since none
// of the currently used Fluent icon paths contain arc segments.
static bool SvgParsePathToGeometry(const char* d, ID2D1PathGeometry** ppOut) {
    if (!g_d2dFactory) return false;
    Microsoft::WRL::ComPtr<ID2D1PathGeometry> geom;
    if (FAILED(g_d2dFactory->CreatePathGeometry(&geom))) return false;
    Microsoft::WRL::ComPtr<ID2D1GeometrySink> sink;
    if (FAILED(geom->Open(&sink))) return false;
    sink->SetFillMode(D2D1_FILL_MODE_WINDING);
    const char* p = d;
    float cx = 0, cy = 0;
    float startX = 0, startY = 0;
    float lastCtrlX = 0, lastCtrlY = 0;
    char lastCmd = 0;
    bool figOpen = false;
    auto skipSep = [&]() { while (*p == ' ' || *p == ',' || *p == '\n' || *p == '\t' || *p == '\r') ++p; };
    auto readF = [&](float& v) -> bool {
        char* e; v = strtof(p, &e); if (e == p) return false;
        p = e; skipSep(); return true;
    };
    auto isNum = [&]() -> bool { return *p == '-' || *p == '+' || *p == '.' || (*p >= '0' && *p <= '9'); };
    auto closeIfOpen = [&](D2D1_FIGURE_END end) { if (figOpen) { sink->EndFigure(end); figOpen = false; } };
    while (*p) {
        skipSep(); if (!*p) break;
        char cmd;
        if (isNum() && lastCmd) {
            cmd = (lastCmd == 'M') ? 'L' : (lastCmd == 'm') ? 'l' : lastCmd;
        } else {
            cmd = *p++; skipSep();
        }
        bool rel = (cmd >= 'a' && cmd <= 'z');
        switch (cmd) {
        case 'M': case 'm': {
            float x, y; if (!readF(x) || !readF(y)) { lastCmd = 0; break; }
            if (rel) { x += cx; y += cy; }
            closeIfOpen(D2D1_FIGURE_END_OPEN);
            sink->BeginFigure(D2D1::Point2F(x, y), D2D1_FIGURE_BEGIN_FILLED);
            figOpen = true; cx = x; cy = y; startX = x; startY = y;
            lastCmd = cmd; break;
        }
        case 'L': case 'l': {
            float x, y; if (!readF(x) || !readF(y)) { lastCmd = 0; break; }
            if (rel) { x += cx; y += cy; }
            sink->AddLine(D2D1::Point2F(x, y)); cx = x; cy = y;
            lastCmd = cmd; break;
        }
        case 'H': case 'h': {
            float x; if (!readF(x)) { lastCmd = 0; break; }
            if (rel) x += cx;
            sink->AddLine(D2D1::Point2F(x, cy)); cx = x;
            lastCmd = cmd; break;
        }
        case 'V': case 'v': {
            float y; if (!readF(y)) { lastCmd = 0; break; }
            if (rel) y += cy;
            sink->AddLine(D2D1::Point2F(cx, y)); cy = y;
            lastCmd = cmd; break;
        }
        case 'C': case 'c': {
            float x1, y1, x2, y2, x, y;
            while (readF(x1) && readF(y1) && readF(x2) && readF(y2) && readF(x) && readF(y)) {
                float ax1 = x1, ay1 = y1, ax2 = x2, ay2 = y2, ax = x, ay = y;
                if (rel) { ax1 += cx; ay1 += cy; ax2 += cx; ay2 += cy; ax += cx; ay += cy; }
                sink->AddBezier(D2D1::BezierSegment(
                    D2D1::Point2F(ax1, ay1), D2D1::Point2F(ax2, ay2), D2D1::Point2F(ax, ay)));
                lastCtrlX = ax2; lastCtrlY = ay2; cx = ax; cy = ay;
                if (!isNum()) break;
            }
            lastCmd = cmd; break;
        }
        case 'S': case 's': {
            float x2, y2, x, y;
            if (!readF(x2) || !readF(y2) || !readF(x) || !readF(y)) { lastCmd = 0; break; }
            if (rel) { x2 += cx; y2 += cy; x += cx; y += cy; }
            float x1 = (lastCmd == 'C' || lastCmd == 'c' || lastCmd == 'S' || lastCmd == 's')
                ? 2 * cx - lastCtrlX : cx;
            float y1 = (lastCmd == 'C' || lastCmd == 'c' || lastCmd == 'S' || lastCmd == 's')
                ? 2 * cy - lastCtrlY : cy;
            sink->AddBezier(D2D1::BezierSegment(
                D2D1::Point2F(x1, y1), D2D1::Point2F(x2, y2), D2D1::Point2F(x, y)));
            lastCtrlX = x2; lastCtrlY = y2; cx = x; cy = y;
            lastCmd = cmd; break;
        }
        case 'Q': case 'q': {
            float x1, y1, x, y;
            if (!readF(x1) || !readF(y1) || !readF(x) || !readF(y)) { lastCmd = 0; break; }
            if (rel) { x1 += cx; y1 += cy; x += cx; y += cy; }
            float c1x = cx + 2.0f / 3.0f * (x1 - cx);
            float c1y = cy + 2.0f / 3.0f * (y1 - cy);
            float c2x = x + 2.0f / 3.0f * (x1 - x);
            float c2y = y + 2.0f / 3.0f * (y1 - y);
            sink->AddBezier(D2D1::BezierSegment(
                D2D1::Point2F(c1x, c1y), D2D1::Point2F(c2x, c2y), D2D1::Point2F(x, y)));
            lastCtrlX = x1; lastCtrlY = y1; cx = x; cy = y;
            lastCmd = cmd; break;
        }
        case 'T': case 't': {
            float x, y;
            if (!readF(x) || !readF(y)) { lastCmd = 0; break; }
            if (rel) { x += cx; y += cy; }
            float x1 = (lastCmd == 'Q' || lastCmd == 'q' || lastCmd == 'T' || lastCmd == 't')
                ? 2 * cx - lastCtrlX : cx;
            float y1 = (lastCmd == 'Q' || lastCmd == 'q' || lastCmd == 'T' || lastCmd == 't')
                ? 2 * cy - lastCtrlY : cy;
            float c1x = cx + 2.0f / 3.0f * (x1 - cx);
            float c1y = cy + 2.0f / 3.0f * (y1 - cy);
            float c2x = x + 2.0f / 3.0f * (x1 - x);
            float c2y = y + 2.0f / 3.0f * (y1 - y);
            sink->AddBezier(D2D1::BezierSegment(
                D2D1::Point2F(c1x, c1y), D2D1::Point2F(c2x, c2y), D2D1::Point2F(x, y)));
            lastCtrlX = x1; lastCtrlY = y1; cx = x; cy = y;
            lastCmd = cmd; break;
        }
        case 'A': case 'a': {
            float rx, ry, xrot, laf, swf, x, y;
            if (!readF(rx) || !readF(ry) || !readF(xrot) || !readF(laf) || !readF(swf) ||
                !readF(x) || !readF(y)) { lastCmd = 0; break; }
            if (rel) { x += cx; y += cy; }
            sink->AddLine(D2D1::Point2F(x, y));
            cx = x; cy = y;
            lastCmd = cmd; break;
        }
        case 'Z': case 'z':
            closeIfOpen(D2D1_FIGURE_END_CLOSED);
            cx = startX; cy = startY;
            lastCmd = 0; break;
        default:
            lastCmd = 0; break;
        }
    }
    closeIfOpen(D2D1_FIGURE_END_OPEN);
    if (FAILED(sink->Close())) return false;
    *ppOut = geom.Detach();
    return true;
}

// Renders one SVG geometry into `rc` using uniform scale + center fit.
// Bounds are computed from the geometry itself via GetBounds — no hardcoded BB needed.
static void DrawSvgGeom(HDC hdc, const RECT& rc, COLORREF cr,
                        ID2D1PathGeometry* geom, float extraScale = 1.0f,
                        float rotationDeg = 0.0f) {
    Microsoft::WRL::ComPtr<ID2D1DCRenderTarget> rt;
    {
        ID2D1DCRenderTarget* raw = nullptr;
        RECT rcCopy = rc;
        if (FAILED(CreateBoundD2DRenderTarget(hdc, &rcCopy, g_d2dFactory, &raw)) || !raw) return;
        rt.Attach(raw);
    }
    D2D1_RECT_F bb;
    if (FAILED(geom->GetBounds(nullptr, &bb))) return;
    const float contentW = bb.right  - bb.left;
    const float contentH = bb.bottom - bb.top;
    if (contentW <= 0 || contentH <= 0) return;
    const float targetW = float(rc.right  - rc.left);
    const float targetH = float(rc.bottom - rc.top);
    const float scale = std::min(targetW / contentW, targetH / contentH) * extraScale;
    const float offX  = (targetW - contentW * scale) / 2.0f - bb.left * scale;
    const float offY  = (targetH - contentH * scale) / 2.0f - bb.top  * scale;
    const D2D1_COLOR_F clr = {
        GetRValue(cr) / 255.f, GetGValue(cr) / 255.f, GetBValue(cr) / 255.f, 1.0f };
    rt->BeginDraw();
    D2D1::Matrix3x2F transform = D2D1::Matrix3x2F(scale, 0, 0, scale, offX, offY);
    if (rotationDeg != 0.0f) {
        transform = transform * D2D1::Matrix3x2F::Rotation(rotationDeg,
            D2D1::Point2F(targetW / 2.0f, targetH / 2.0f));
    }
    rt->SetTransform(transform);
    if (ID2D1SolidColorBrush* brush = GetCachedSolidBrush(rt.Get(), clr))
        rt->FillGeometry(geom, brush);
    rt->SetTransform(D2D1::Matrix3x2F::Identity());
    if (rt->EndDraw() == D2DERR_RECREATE_TARGET) {
        rt.Reset();
        CachedTlsRTRecreate();
    }
}

